Javascript.logic:
var value = Services.getValue(LocalWarrantNumber.dataBinding);
if (!CaseManUtils.isBlank(value) && null != value)
{
	searchWarrants();
}

Javascript.miscCode:
	Status_RunReportButton.validationList = ["LocalWarrantNumber"];
	var SEARCH_RESULTS_XPATH = PAGE_XPATH + "/tmp/Warrants";
	Status_RunReportButton.enableOn = [SEARCH_RESULTS_XPATH];
	Status_RunReportButton.isEnabled = function()
	{
		var errCode = validateWarrant();
		if (errCode == null)
		{
			return true;
		}
		else
		{
			return false;
		}
	}			
	function searchWarrants()
	{
		var localWarrantNumber = Services.getValue(LocalWarrantNumber.dataBinding);				
	    //Call Search Service now
		var params = new ServiceParams();
		params.addSimpleParameter("localNumber", localWarrantNumber);
		
		//Wildcard search removed, might as well delete them.
		/*
		params.addSimpleParameter("warrantNumber", "%");
		params.addSimpleParameter("caseNumber", "%");
		params.addSimpleParameter("CONumber", "%");
		params.addSimpleParameter("issueDate", "%");
		params.addSimpleParameter("issuedBy", "%");
		*/
		
		Services.callService("searchWarrants", params, LocalWarrantNumber, true);			
	}
	
	LocalWarrantNumber.onSuccess = function(dom) {
	    if(dom != null) {
	        var node = dom.selectSingleNode("/ds/Warrants");
	        Services.replaceNode(SEARCH_RESULTS_XPATH, node);
	        
	        var count = Services.countNodes(SEARCH_RESULTS_XPATH + "/Warrant");
	        if(count == 0) {
	           alert("Local Warrant Number does not exist."); 
			   Services.setValue(LocalWarrantNumber.dataBinding, "");
	        } else if(count >= 1) {
	        	//alert("Valid Warrant Number"); 
	        }
	    }
	}
	
	function validateWarrant()
	{
		var errCode = null;
		//alert("Checking for Warrant Number. Click Ok.");
		var count = Services.countNodes(SEARCH_RESULTS_XPATH + "/Warrant");
		if(count == 0) {
           errCode = ErrorCode.getErrorCode("CaseMan_noLocalWarrantExists_Msg");
        }
        return errCode;
	}
